-- ----------------------------
-- Table structure for agent_tools
-- ----------------------------
DROP TABLE IF EXISTS `agent_tools`;
CREATE TABLE `agent_tools`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT,
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '工具唯一名称，供代码/LLM调用',
  `display_name` varchar(150) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '展示名/别名',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '功能描述，供 LLM prompt',
  `params_schema` json NULL COMMENT '参数定义（JSON Schema 或自定义格式）',
  `version` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '1.0.0' COMMENT '工具版本',
  `enabled` tinyint(1) NULL DEFAULT 1 COMMENT '是否启用',
  `tags` json NULL COMMENT '标签/分类，如[\"db\",\"unsafe\"]',
  `roles_allowed` json NULL COMMENT '允许调用的角色/租户列表',
  `rate_limit` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '速率限制配置，如 10/m',
  `created_at` timestamp(0) NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp(0) NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `name`(`name`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = 'LLM 可调用工具元数据表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of agent_tools
-- ----------------------------
INSERT INTO `agent_tools` VALUES (1, 'backend_api', '后端 API 代理', '按 resource/action 组合动态调用后端接口，转发 path/query/body，返回原始结果并附带展示提示。', '{\"type\": \"object\", \"required\": [\"resource\", \"action\"], \"properties\": {\"action\": {\"type\": \"string\", \"description\": \"动作名，如 list_all/get_by_id\"}, \"params\": {\"type\": \"object\", \"description\": \"查询参数 (GET)\"}, \"payload\": {\"type\": \"object\", \"description\": \"请求体 (POST/PUT)\"}, \"resource\": {\"type\": \"string\", \"description\": \"业务资源，如 product/order/user\"}, \"authorization\": {\"type\": \"string\", \"description\": \"可选覆盖默认 Authorization 头的 token\"}, \"pathVariables\": {\"type\": \"object\", \"description\": \"路径变量，例如 {\\\"id\\\":1}\"}}}', '1.0.0', 1, '[\"proxy\", \"http\"]', '[\"admin\", \"agent\"]', '20/m', '2025-12-04 15:32:25', '2025-12-04 15:32:25');

-- ----------------------------
-- Table structure for api_routes
-- ----------------------------
DROP TABLE IF EXISTS `api_routes`;
CREATE TABLE `api_routes`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT,
  `resource` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `action` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `http_method` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `path_template` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `path_params` json NULL,
  `operation_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `description` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `enabled` tinyint(1) NOT NULL DEFAULT 1,
  `query_schema` json NULL,
  `body_schema` json NULL,
  `created_at` timestamp(0) NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp(0) NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_resource_action`(`resource`, `action`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 27 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '接口管理' ROW_FORMAT = Dynamic;

