  `product_id` bigint(0) NOT NULL COMMENT '商品编号',
  `quantity` int(0) NOT NULL DEFAULT 1 COMMENT '数量',
  `price` decimal(10, 2) NOT NULL COMMENT '加入时的单价',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_cart_product`(`user_name`, `product_id`) USING BTREE,
  UNIQUE INDEX `idx_cart_item_user_product`(`user_name`, `product_id`) USING BTREE,
  INDEX `idx_product`(`product_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 24 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '购物车明细表' ROW_FORMAT = Dynamic;

