-- ----------------------------
-- Table structure for category
-- ----------------------------
DROP TABLE IF EXISTS `category`;
CREATE TABLE `category`  (
  `category_id` bigint(0) NOT NULL COMMENT '类目ID',
  `parent_category_id` bigint(0) NOT NULL DEFAULT 0 COMMENT '父类目ID，0表示根节点',
  `category_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '类目名称',
  `category_level` tinyint(0) NOT NULL COMMENT '类目层级，从1开始',
  `category_path` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '类目路径，如 1/12/123',
  `is_leaf` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否叶子节点：0否 1是',
  `sort_order` int(0) NOT NULL DEFAULT 0 COMMENT '排序值，越小越靠前',
  `status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'enabled' COMMENT '状态：enabled/disabled',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '更新时间',
  PRIMARY KEY (`category_id`) USING BTREE,
  INDEX `idx_parent_category_id`(`parent_category_id`) USING BTREE,
  INDEX `idx_category_level`(`category_level`) USING BTREE,
  INDEX `idx_status_sort_order`(`status`, `sort_order`) USING BTREE,
  INDEX `idx_category_path`(`category_path`(255)) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '类目树表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for chat_feedback
-- ----------------------------
DROP TABLE IF EXISTS `chat_feedback`;
CREATE TABLE `chat_feedback`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT,
  `session_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '浼氳瘽ID',
  `user_question` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '鐢ㄦ埛闂??',
  `ai_answer` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT 'AI鍥炵瓟',
  `knowledge_ids` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '浣跨敤鐨勭煡璇咺D',
  `is_helpful` tinyint(0) NULL DEFAULT NULL COMMENT '鏄?惁鏈夊府鍔╋細0-鍚︼紝1-鏄',
  `feedback_text` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '鍙嶉?鍐呭?',
  `created_at` timestamp(0) NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_session`(`session_id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for community_feed
-- ----------------------------
DROP TABLE IF EXISTS `community_feed`;
CREATE TABLE `community_feed`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT,
  `user_id` bigint(0) NOT NULL,
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `images` json NULL,
  `visibility` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'PUBLIC',
  `location_text` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP(0),
  `likes_count` int(0) NOT NULL DEFAULT 0,
  `comments_count` int(0) NOT NULL DEFAULT 0,
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'ACTIVE',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_feed_user`(`user_id`, `created_at`) USING BTREE,
  INDEX `idx_feed_created`(`created_at`) USING BTREE,
  INDEX `idx_feed_status`(`status`) USING BTREE,
  INDEX `idx_feed_visibility`(`visibility`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 17 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

