-- ----------------------------
-- Table structure for event_search_snapshot
-- ----------------------------
DROP TABLE IF EXISTS `event_search_snapshot`;
CREATE TABLE `event_search_snapshot`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `event_id` bigint(0) NOT NULL COMMENT '活动ID',
  `organizer_id` bigint(0) NOT NULL COMMENT '主办方ID',
  `venue_id` bigint(0) NULL DEFAULT NULL COMMENT '场馆/门店ID',
  `venue_name` varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '场馆/门店名称',
  `title` varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '活动标题',
  `subtitle` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '活动副标题',
  `summary_text` varchar(2000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '活动摘要',
  `category_id` bigint(0) NOT NULL COMMENT '主类目ID',
  `category_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '主类目名称',
  `category_path` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '类目路径',
  `tag_ids` json NULL COMMENT '标签ID数组JSON',
  `tag_names` json NULL COMMENT '标签名称数组JSON',
  `audience_tags` json NULL COMMENT '适合人群标签JSON',
  `city_id` bigint(0) NULL DEFAULT NULL COMMENT '城市ID',
  `city_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '城市名称',
  `district_id` bigint(0) NULL DEFAULT NULL COMMENT '区县ID',
  `district_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '区县名称',
  `lat` decimal(10, 7) NULL DEFAULT NULL COMMENT '纬度',
  `lng` decimal(10, 7) NULL DEFAULT NULL COMMENT '经度',
  `min_price` decimal(12, 2) NULL DEFAULT NULL COMMENT '最低价格',
  `max_price` decimal(12, 2) NULL DEFAULT NULL COMMENT '最高价格',
  `event_start_time` datetime(0) NULL DEFAULT NULL COMMENT '活动开始时间',
  `event_end_time` datetime(0) NULL DEFAULT NULL COMMENT '活动结束时间',
  `weekday_mask` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '星期掩码，如 1,2,3,4,5',
  `searchable_status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'disabled' COMMENT '搜索状态：searchable/not_searchable/expired/draft/disabled',
  `publish_status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'off_shelf' COMMENT '上架状态：on_shelf/off_shelf',
  `audit_status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending' COMMENT '审核状态：pending/approved/rejected',
  `visible_status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'hidden' COMMENT '可见状态：visible/hidden',
  `sales_count` bigint(0) NOT NULL DEFAULT 0 COMMENT '销量/报名量',
  `rating` decimal(3, 2) NOT NULL DEFAULT 0.00 COMMENT '评分',
  `hot_score` decimal(14, 4) NOT NULL DEFAULT 0.0000 COMMENT '热度分',
  `recommend_score` decimal(14, 4) NOT NULL DEFAULT 0.0000 COMMENT '推荐综合分',
  `created_at` datetime(0) NOT NULL COMMENT '源对象创建时间',
  `updated_at` datetime(0) NOT NULL COMMENT '源对象更新时间',
  `searchable_updated_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '快照可搜索更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_event_id`(`event_id`) USING BTREE,
  INDEX `idx_category_id`(`category_id`) USING BTREE,
  INDEX `idx_city_district`(`city_id`, `district_id`) USING BTREE,
  INDEX `idx_min_price`(`min_price`) USING BTREE,
  INDEX `idx_max_price`(`max_price`) USING BTREE,
  INDEX `idx_event_start_time`(`event_start_time`) USING BTREE,
  INDEX `idx_event_end_time`(`event_end_time`) USING BTREE,
  INDEX `idx_sales_count`(`sales_count`) USING BTREE,
  INDEX `idx_rating`(`rating`) USING BTREE,
  INDEX `idx_hot_score`(`hot_score`) USING BTREE,
  INDEX `idx_recommend_score`(`recommend_score`) USING BTREE,
  INDEX `idx_created_at`(`created_at`) USING BTREE,
  INDEX `idx_updated_at`(`updated_at`) USING BTREE,
  INDEX `idx_searchable_updated_at`(`searchable_updated_at`) USING BTREE,
  INDEX `idx_search_filter_status`(`searchable_status`, `publish_status`, `audit_status`, `visible_status`) USING BTREE,
  INDEX `idx_search_filter_city_category_time`(`searchable_status`, `publish_status`, `audit_status`, `visible_status`, `city_id`, `category_id`, `event_start_time`) USING BTREE,
  INDEX `idx_venue_id`(`venue_id`) USING BTREE,
  INDEX `idx_organizer_id`(`organizer_id`) USING BTREE,
  INDEX `idx_lat_lng`(`lat`, `lng`) USING BTREE,
  INDEX `idx_category_path`(`category_path`(255)) USING BTREE,
  INDEX `idx_title`(`title`) USING BTREE,
  INDEX `idx_venue_name`(`venue_name`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 12 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '活动搜索快照表' ROW_FORMAT = Dynamic;

