-- ----------------------------
-- Table structure for governance_replay_tool_ios
-- ----------------------------
DROP TABLE IF EXISTS `governance_replay_tool_ios`;
CREATE TABLE `governance_replay_tool_ios`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT,
  `replay_record_id` bigint(0) NOT NULL,
  `step_order` int(0) NOT NULL DEFAULT 0,
  `step_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `tool_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `purpose` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `output_key` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `optional_step` tinyint(0) NOT NULL DEFAULT 0,
  `execution_status` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `input_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL,
  `output_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL,
  `created_at` datetime(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_governance_replay_tool_ios_record_id`(`replay_record_id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for knowledge_base
-- ----------------------------
DROP TABLE IF EXISTS `knowledge_base`;
CREATE TABLE `knowledge_base`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT,
  `category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '鍒嗙被锛歠aq/guide/rule/policy',
  `doc_type` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'faq',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '鏍囬?',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '鍐呭?',
  `summary` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `keywords` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '鍏抽敭璇嶏紙閫楀彿鍒嗛殧锛',
  `related_questions` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '鐩稿叧闂??锛圝SON鏁扮粍锛',
  `source_system` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'cms',
  `entity_type` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `entity_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `city_ids` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `category_ids` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `tag_ids` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `version` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'v1',
  `priority` int(0) NULL DEFAULT 0,
  `owner` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `language` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'zh-CN',
  `effective_from` timestamp(0) NULL DEFAULT NULL,
  `effective_to` timestamp(0) NULL DEFAULT NULL,
  `published_at` timestamp(0) NULL DEFAULT NULL,
  `view_count` int(0) NULL DEFAULT 0 COMMENT '鏌ョ湅娆℃暟',
  `helpful_count` int(0) NULL DEFAULT 0 COMMENT '鏈夊府鍔╂?鏁',
  `status` tinyint(0) NULL DEFAULT 1 COMMENT '鐘舵?锛?-绂佺敤锛?-鍚?敤',
  `created_at` timestamp(0) NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp(0) NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_category`(`category`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE,
  INDEX `idx_doc_type`(`doc_type`) USING BTREE,
  INDEX `idx_entity`(`entity_type`, `entity_id`) USING BTREE,
  INDEX `idx_effective`(`effective_from`, `effective_to`) USING BTREE,
  FULLTEXT INDEX `idx_content`(`title`, `content`, `keywords`)
) ENGINE = InnoDB AUTO_INCREMENT = 7 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of knowledge_base
-- ----------------------------
INSERT INTO `knowledge_base` VALUES (1, 'faq', 'faq', '如何发布商品？', '发布商品的步骤：\n1. 登录账号\n2. 点击\"发布商品\"按钮\n3. 填写商品信息（标题、描述、价格、位置等）\n4. 上传商品图片\n5. 点击\"发布\"按钮\n\n注意：商品信息需要真实准确，图片需清晰可见。', NULL, '发布商品,上传商品,商品发布', NULL, 'cms', NULL, NULL, NULL, NULL, NULL, 'v1', 0, NULL, 'zh-CN', NULL, NULL, NULL, 0, 0, 1, '2026-03-16 22:08:44', '2026-03-16 22:08:44');
INSERT INTO `knowledge_base` VALUES (2, 'faq', 'faq', '如何报名活动？', '报名活动的步骤：\n1. 浏览活动列表\n2. 点击感兴趣的活动\n3. 查看活动详情和要求\n4. 点击\"报名\"按钮\n5. 填写报名信息\n6. 确认提交\n\n报名成功后会收到通知。', NULL, '报名活动,参加活动,活动报名', NULL, 'cms', NULL, NULL, NULL, NULL, NULL, 'v1', 0, NULL, 'zh-CN', NULL, NULL, NULL, 0, 0, 1, '2026-03-16 22:08:44', '2026-03-16 22:08:44');
INSERT INTO `knowledge_base` VALUES (3, 'faq', 'faq', '如何查看附近的商品？', '查看附近商品的方法：\n1. 在首页或商品列表页\n2. 系统会自动获取您的位置\n3. 显示附近的商品列表\n4. 可以调整搜索范围（1km、3km、5km等）\n\n您也可以手动输入地址搜索特定区域的商品。', NULL, '附近商品,查看商品,搜索商品', NULL, 'cms', NULL, NULL, NULL, NULL, NULL, 'v1', 0, NULL, 'zh-CN', NULL, NULL, NULL, 0, 0, 1, '2026-03-16 22:08:44', '2026-03-16 22:08:44');
INSERT INTO `knowledge_base` VALUES (4, 'guide', 'faq', '商品发布规范', '商品发布规范：\n1. 标题：简洁明了，不超过50字\n2. 描述：详细描述商品状态、规格等\n3. 价格：真实合理的价格\n4. 图片：至少1张，最多9张，清晰展示商品\n5. 位置：准确的交易地点\n\n禁止发布违禁品、虚假信息。', NULL, '发布规范,商品规范,发布要求', NULL, 'cms', NULL, NULL, NULL, NULL, NULL, 'v1', 0, NULL, 'zh-CN', NULL, NULL, NULL, 0, 0, 1, '2026-03-16 22:08:44', '2026-03-16 22:08:44');
INSERT INTO `knowledge_base` VALUES (5, 'guide', 'faq', '活动创建指南', '创建活动的要求：\n1. 活动标题：吸引人且准确\n2. 活动时间：明确的开始和结束时间\n3. 活动地点：详细的地址信息\n4. 活动描述：活动内容、流程、注意事项\n5. 人数限制：根据实际情况设置\n\n活动需要审核通过后才能发布。', NULL, '创建活动,活动指南,发布活动', NULL, 'cms', NULL, NULL, NULL, NULL, NULL, 'v1', 0, NULL, 'zh-CN', NULL, NULL, NULL, 0, 0, 1, '2026-03-16 22:08:44', '2026-03-16 22:08:44');
INSERT INTO `knowledge_base` VALUES (6, 'rule', 'faq', '交易安全规则', '为保障交易安全：\n1. 建议当面交易，验货后付款\n2. 不要提前转账或支付定金\n3. 注意保护个人隐私信息\n4. 遇到可疑情况及时举报\n5. 保留交易凭证\n\n平台不对私下交易负责，请谨慎交易。', NULL, '交易规则,安全规则,交易安全', NULL, 'cms', NULL, NULL, NULL, NULL, NULL, 'v1', 0, NULL, 'zh-CN', NULL, NULL, NULL, 0, 0, 1, '2026-03-16 22:08:44', '2026-03-16 22:08:44');
INSERT INTO `knowledge_base` VALUES (7, 'rule', 'faq', '社区公约', '社区公约：\n1. 尊重他人，文明交流\n2. 不发布违法违规内容\n3. 不恶意骚扰其他用户\n4. 不发布虚假信息\n5. 保护个人隐私\n\n违反公约将受到警告、禁言或封号处理。', NULL, '社区公约,用户规则,行为规范', NULL, 'cms', NULL, NULL, NULL, NULL, NULL, 'v1', 0, NULL, 'zh-CN', NULL, NULL, NULL, 0, 0, 1, '2026-03-16 22:08:44', '2026-03-16 22:08:44');

-- ----------------------------
-- Table structure for knowledge_chunk
-- ----------------------------
DROP TABLE IF EXISTS `knowledge_chunk`;
CREATE TABLE `knowledge_chunk`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT,
  `knowledge_id` bigint(0) NOT NULL COMMENT '知识 ID',
  `chunk_no` int(0) NOT NULL COMMENT 'chunk 序号',
  `chunk_type` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'chunk 类型',
  `chunk_text` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'chunk 文本',
  `metadata_json` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT 'chunk 元数据 JSON',
  `status` tinyint(0) NULL DEFAULT 1 COMMENT '状态：0-禁用，1-启用',
  `created_at` timestamp(0) NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp(0) NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_knowledge_chunk`(`knowledge_id`, `chunk_no`) USING BTREE,
  INDEX `idx_chunk_status`(`status`) USING BTREE,
  FULLTEXT INDEX `idx_chunk_text`(`chunk_text`),
  CONSTRAINT `knowledge_chunk_ibfk_1` FOREIGN KEY (`knowledge_id`) REFERENCES `knowledge_base` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for knowledge_vector
-- ----------------------------
DROP TABLE IF EXISTS `knowledge_vector`;
CREATE TABLE `knowledge_vector`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT,
  `knowledge_id` bigint(0) NOT NULL COMMENT '鐭ヨ瘑ID',
  `vector_data` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '鍚戦噺鏁版嵁锛圝SON锛',
  `created_at` timestamp(0) NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_knowledge`(`knowledge_id`) USING BTREE,
  CONSTRAINT `knowledge_vector_ibfk_1` FOREIGN KEY (`knowledge_id`) REFERENCES `knowledge_base` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 7 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

-- ----------------------------
