-- ----------------------------
-- Table structure for local_activity
-- ----------------------------
DROP TABLE IF EXISTS `local_activity`;
CREATE TABLE `local_activity`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT,
  `organizer_user_id` int(0) NOT NULL COMMENT '活动组织者 = users.user_id',
  `title` varchar(120) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '活动标题',
  `subtitle` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '副标题',
  `category_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '分类编码',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '详细描述',
  `location_text` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '位置文字（如“星巴克·天河店”）',
  `address` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '具体地址',
  `latitude` double NULL DEFAULT NULL COMMENT '纬度',
  `longitude` double NULL DEFAULT NULL COMMENT '经度',
  `cover_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '封面图 URL',
  `fee_type` enum('FREE','AA','PAID') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'FREE' COMMENT '收费类型',
  `fee_amount` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '费用（元）',
  `capacity` int(0) NULL DEFAULT 0 COMMENT '人数上限（0=不限）',
  `allow_waitlist` tinyint(1) NULL DEFAULT 1 COMMENT '是否允许候补',
  `require_checkin` tinyint(1) NULL DEFAULT 1 COMMENT '是否需要签到',
  `status` enum('DRAFT','REVIEWING','PUBLISHED','CANCELLED') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'DRAFT' COMMENT '状态',
  `start_at` datetime(0) NOT NULL COMMENT '活动开始时间',
  `end_at` datetime(0) NOT NULL COMMENT '活动结束时间',
  `contact_phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '联系电话',
  `reminder_minutes` int(0) NULL DEFAULT 1440 COMMENT '提前提醒分钟数',
  `review_note` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '审核备注',
  `created_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_activity_start`(`start_at`) USING BTREE,
  INDEX `idx_activity_status_start`(`status`, `start_at`) USING BTREE,
  INDEX `activity_organizer_idx`(`organizer_user_id`) USING BTREE,
  CONSTRAINT `fk_activity_user1` FOREIGN KEY (`organizer_user_id`) REFERENCES `users` (`user_id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE = InnoDB AUTO_INCREMENT = 26 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '本地活动主表' ROW_FORMAT = Dynamic;

-- ----------------------------
