  `end_at` datetime(0) NOT NULL,
  `contact_phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `reminder_minutes` int(0) NULL DEFAULT 1440,
