-- ----------------------------
-- Table structure for notifications
-- ----------------------------
DROP TABLE IF EXISTS `notifications`;
CREATE TABLE `notifications`  (
  `id` bigint(0) UNSIGNED NOT NULL AUTO_INCREMENT,
  `msg_id` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '消息幂等键',
  `user_id` bigint(0) UNSIGNED NOT NULL COMMENT '接收用户',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '通知标题',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '通知内容',
  `type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '通知类型，如 ITEM_PUBLISHED、EVENT_REMINDER',
  `priority` int(0) NULL DEFAULT 0 COMMENT '优先级，越大越靠前',
  `read_status` tinyint(1) NOT NULL DEFAULT 0 COMMENT '0=未读，1=已读',
  `read_at` datetime(0) NULL DEFAULT NULL COMMENT '阅读时间',
  `link_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '点击跳转链接（可选）',
  `meta` json NULL COMMENT '业务相关的数据（可选，如商品ID，活动ID）',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `expire_at` datetime(0) NULL DEFAULT NULL COMMENT '过期时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_notifications_msgid_user`(`msg_id`, `user_id`) USING BTREE,
  INDEX `idx_user_status_created`(`user_id`, `read_status`, `created_at`) USING BTREE,
  INDEX `idx_user_created`(`user_id`, `created_at`) USING BTREE,
  INDEX `idx_notifications_user_read`(`user_id`, `read_status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 33 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '系统通知表' ROW_FORMAT = Dynamic;

