-- ----------------------------
-- Table structure for query_expand_dict
-- ----------------------------
DROP TABLE IF EXISTS `query_expand_dict`;
CREATE TABLE `query_expand_dict`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `query_term` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '原始查询词',
  `expand_terms_json` json NULL COMMENT '扩展词列表JSON，如 [\"手办\",\"模型\",\"公仔\"]',
  `expand_categories_json` json NULL COMMENT '扩展类目JSON，如 [1001,1002]',
  `expand_tags_json` json NULL COMMENT '扩展标签JSON，如 [2001,2002]',
  `status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'enabled' COMMENT '状态：enabled/disabled',
  `updated_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '更新时间',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_query_term`(`query_term`) USING BTREE,
  INDEX `idx_status_updated_at`(`status`, `updated_at`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '高频查询扩展词典表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for store_search_snapshot
-- ----------------------------
DROP TABLE IF EXISTS `store_search_snapshot`;
CREATE TABLE `store_search_snapshot`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `store_id` bigint(0) NOT NULL COMMENT '门店ID',
  `merchant_id` bigint(0) NOT NULL COMMENT '商户ID',
  `store_name` varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '门店名称',
  `title` varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '门店标题',
  `summary_text` varchar(2000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '门店摘要',
  `category_id` bigint(0) NULL DEFAULT NULL COMMENT '主类目ID',
  `category_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '主类目名称',
  `category_path` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '类目路径',
  `tag_names` json NULL COMMENT '标签名称数组JSON',
  `city_id` bigint(0) NULL DEFAULT NULL COMMENT '城市ID',
  `district_id` bigint(0) NULL DEFAULT NULL COMMENT '区县ID',
  `business_area_id` bigint(0) NULL DEFAULT NULL COMMENT '商圈ID',
  `lat` decimal(10, 7) NULL DEFAULT NULL COMMENT '纬度',
  `lng` decimal(10, 7) NULL DEFAULT NULL COMMENT '经度',
  `avg_price` decimal(12, 2) NULL DEFAULT NULL COMMENT '人均/均价',
  `rating` decimal(3, 2) NOT NULL DEFAULT 0.00 COMMENT '评分',
  `review_count` bigint(0) NOT NULL DEFAULT 0 COMMENT '评价数',
  `hot_score` decimal(14, 4) NOT NULL DEFAULT 0.0000 COMMENT '热度分',
  `searchable_status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'disabled' COMMENT '搜索状态：searchable/not_searchable/expired/draft/disabled',
  `publish_status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'off_shelf' COMMENT '发布状态：on_shelf/off_shelf',
  `visible_status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'hidden' COMMENT '可见状态：visible/hidden',
  `base_open_time_desc` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '基础营业时间说明',
  `created_at` datetime(0) NOT NULL COMMENT '源对象创建时间',
  `updated_at` datetime(0) NOT NULL COMMENT '源对象更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_store_id`(`store_id`) USING BTREE,
  INDEX `idx_merchant_id`(`merchant_id`) USING BTREE,
  INDEX `idx_category_id`(`category_id`) USING BTREE,
  INDEX `idx_city_district_biz`(`city_id`, `district_id`, `business_area_id`) USING BTREE,
  INDEX `idx_avg_price`(`avg_price`) USING BTREE,
  INDEX `idx_rating`(`rating`) USING BTREE,
  INDEX `idx_review_count`(`review_count`) USING BTREE,
  INDEX `idx_hot_score`(`hot_score`) USING BTREE,
  INDEX `idx_created_at`(`created_at`) USING BTREE,
  INDEX `idx_updated_at`(`updated_at`) USING BTREE,
  INDEX `idx_search_filter_status`(`searchable_status`, `publish_status`, `visible_status`) USING BTREE,
  INDEX `idx_search_filter_city_category`(`searchable_status`, `publish_status`, `visible_status`, `city_id`, `category_id`) USING BTREE,
  INDEX `idx_lat_lng`(`lat`, `lng`) USING BTREE,
  INDEX `idx_category_path`(`category_path`(255)) USING BTREE,
  INDEX `idx_store_name`(`store_name`) USING BTREE,
  INDEX `idx_title`(`title`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '门店搜索快照表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for tag
-- ----------------------------
DROP TABLE IF EXISTS `tag`;
CREATE TABLE `tag`  (
  `tag_id` bigint(0) NOT NULL COMMENT '标签ID',
  `tag_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '标签名称',
  `tag_type` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'general' COMMENT '标签类型，如 general/audience/scene/feature',
  `status` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'enabled' COMMENT '状态：enabled/disabled',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '更新时间',
  PRIMARY KEY (`tag_id`) USING BTREE,
  UNIQUE INDEX `uk_tag_type_name`(`tag_type`, `tag_name`) USING BTREE,
  INDEX `idx_tag_name`(`tag_name`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '标签表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for topic
-- ----------------------------
DROP TABLE IF EXISTS `topic`;
CREATE TABLE `topic`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT,
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `slug` varchar(120) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `description` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `cover_key` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'ACTIVE',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP(0),
  `feeds_count` int(0) NOT NULL DEFAULT 0,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `name`(`name`) USING BTREE,
  UNIQUE INDEX `slug`(`slug`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for user_products
-- ----------------------------
DROP TABLE IF EXISTS `user_products`;
CREATE TABLE `user_products`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT,
  `user_id` bigint(0) NOT NULL COMMENT '用户ID',
  `product_id` bigint(0) NOT NULL COMMENT '商品SKU ID',
  `created_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime(0) NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 17 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '用户商品表' ROW_FORMAT = Dynamic;

